// CSOS Codegen - Compiles .csos spec to LLVM IRn// Purpose: Parse .csos spec -> Generate LLVM IRnn#include <llvm/IR/LLVMContext.h>n#include <llvm/IR/IRBuilder.h>n#include <llvm/IR/Module.h>n#include <llvm/IR/Verifier.h>n#include <llvm/ExecutionEngine/Orc/LLJIT.h>n#include <llvm/Support/TargetSelect.h>n#include <llvm/Support/raw_ostream.h>n#include <fstream>n#include <sstream>n#include <regex>n#include <map>n#include <iostream>nnnamespace csos {nn// AST Structuresnstruct Atom {n    std::string name;n    std::string formula;n    std::string source;n    std::map<std::string, double> params;n    std::string role;n};nnstruct Ring {n    std::string name;n    std::vector<std::string> atoms;n    std::string purpose;n};nnstruct Agent {n    std::string name;n    std::string mode;n    std::vector<std::string> loop_body;n};nnstruct Law {n    std::string name;n    std::string enforcement;n    std::vector<std::string> enforced_by;n};nn// Parsernclass SpecParser {npublic:n    std::vector<Atom> atoms;n    std::vector<Ring> rings;n    std::vector<Agent> agents;n    std::vector<Law> laws;nn    bool parse(const std::string& path) {n        std::ifstream file(path);n        if (!file.is_open()) return false;nn        std::string line;n        while (std::getline(file, line)) {n            trim(line);n            if (line.empty() || line.substr(0, 2) == "//") continue;nn            if (line.substr(0, 5) == "atom ") {n                Atom a;n                a.name = extract_name(line, "atom ");n                atoms.push_back(a);n            }n            else if (line.substr(0, 5) == "ring ") {n                Ring r;n                r.name = extract_name(line, "ring ");n                rings.push_back(r);n            }n            else if (line.substr(0, 6) == "agent ") {n                Agent ag;n                ag.name = extract_name(line, "agent ");n                agents.push_back(ag);n            }n            else if (line.substr(0, 4) == "law ") {n                Law l;n                l.name = extract_name(line, "law ");n                laws.push_back(l);n            }n        }n        return true;n    }nnprivate:n    std::string extract_name(const std::string& line, const std::string& prefix) {n        size_t start = line.find(prefix) + prefix.size();n        size_t end = line.find("{");n        return line.substr(start, end - start);n    }nn    void trim(std::string& s) {n        s.erase(0, s.find_first_not_of(" \t"));n        s.erase(s.find_last_not_of(" \t") + 1);n    }n};nn// LLVM Codegennclass Codegen {n    llvm::LLVMContext context;n    llvm::IRBuilder<> builder;n    std::unique_ptr<llvm::Module> module;nnpublic:n    Codegen() : builder(context) {n        module = std::make_unique<llvm::Module>("csos_llvm", context);n    }nn    llvm::Function* create_gouterman() {n        llvm::FunctionType* ty = llvm::FunctionType::get(builder.getDoubleTy(), {builder.getDoubleTy()}, false);n        llvm::Function* fn = llvm::Function::Create(ty, llvm::Function::ExternalLinkage, "gouterman_dE", module.get());n        llvm::BasicBlock* entry = llvm::BasicBlock::Create(context, "entry", fn);n        builder.SetInsertPoint(entry);n        llvm::Argument* lambda = fn->getArg(0);n        llvm::Value* h = builder.getConstantFP(llvm::APFloat(6.626e-34));n        llvm::Value* c = builder.getConstantFP(llvm::APFloat(2.998e8));n        llvm::Value* result = builder.CreateFDiv(builder.CreateFMul(h, c), lambda, "dE");n        builder.CreateRet(result);n        return fn;n    }nn    llvm::Function* create_forster() {n        llvm::FunctionType* ty = llvm::FunctionType::get(builder.getDoubleTy(), {builder.getDoubleTy(), builder.getDoubleTy()}, false);n        llvm::Function* fn = llvm::Function::Create(ty, llvm::Function::ExternalLinkage, "forster_kET", module.get());n        llvm::BasicBlock* entry = llvm::BasicBlock::Create(context, "entry", fn);n        builder.SetInsertPoint(entry);n        llvm::Argument* t = fn->getArg(0);n        llvm::Argument* r = fn->getArg(1);n        llvm::Value* one_over_t = builder.CreateFDiv(builder.getConstantFP(llvm::APFloat(1.0)), t, "inv_t");n        llvm::Value* R0 = builder.getConstantFP(llvm::APFloat(1.0));n        llvm::Value* ratio = builder.CreateFDiv(R0, r, "ratio");n        llvm::Value* ratio_pow6 = builder.CreateFMul(ratio, ratio, "r2");n        ratio_pow6 = builder.CreateFMul(ratio_pow6, ratio_pow6, "r4");n        ratio_pow6 = builder.CreateFMul(ratio_pow6, ratio_pow6, "r6");n        llvm::Value* result = builder.CreateFMul(one_over_t, ratio_pow6, "k_ET");n        builder.CreateRet(result);n        return fn;n    }nn    llvm::Function* create_marcus() {n        llvm::FunctionType* ty = llvm::FunctionType::get(builder.getDoubleTy(), {builder.getDoubleTy(), builder.getDoubleTy()}, false);n        llvm::Function* fn = llvm::Function::Create(ty, llvm::Function::ExternalLinkage, "marcus_k", module.get());n        llvm::BasicBlock* entry = llvm::BasicBlock::Create(context, "entry", fn);n        builder.SetInsertPoint(entry);n        llvm::Argument* dG = fn->getArg(0);n        llvm::Argument* lambda = fn->getArg(1);n        llvm::Value* kT = builder.getConstantFP(llvm::APFloat(4.142e-21));n        llvm::Value* num = builder.CreateFMul(builder.CreateFAdd(dG, lambda), builder.CreateFAdd(dG, lambda), "num");n        llvm::Value* denom = builder.CreateFMul(builder.getConstantFP(llvm::APFloat(4.0)), lambda, "den1");n        denom = builder.CreateFMul(denom, kT, "denom");n        llvm::Value* exponent = builder.CreateFNeg(builder.CreateFDiv(num, denom), "exponent");n        llvm::Function* exp_fn = llvm::Intrinsic::getDeclaration(module.get(), llvm::Intrinsic::exp, {builder.getDoubleTy()});n        llvm::Value* result = builder.CreateCall(exp_fn, {exponent}, "k");n        builder.CreateRet(result);n        return fn;n    }nn    llvm::Function* create_mitchell() {n        llvm::FunctionType* ty = llvm::FunctionType::get(builder.getDoubleTy(), {builder.getDoubleTy(), builder.getDoubleTy(), builder.getDoubleTy()}, false);n        llvm::Function* fn = llvm::Function::Create(ty, llvm::Function::ExternalLinkage, "mitchell_dG", module.get());n        llvm::BasicBlock* entry = llvm::BasicBlock::Create(context, "entry", fn);n        builder.SetInsertPoint(entry);n        llvm::Argument* n = fn->getArg(0);n        llvm::Argument* dy = fn->getArg(1);n        llvm::Argument* dpH = fn->getArg(2);n        llvm::Value* F = builder.getConstantFP(llvm::APFloat(96485.0));n        llvm::Value* term1 = builder.CreateFNeg(builder.CreateFMul(builder.CreateFMul(n, F), dy), "term1");n        llvm::Value* R = builder.getConstantFP(llvm::APFloat(8.314));n        llvm::Value* T = builder.getConstantFP(llvm::APFloat(300.0));n        llvm::Value* term2 = builder.CreateFMul(builder.getConstantFP(llvm::APFloat(2.3)), R, "t2a");n        term2 = builder.CreateFMul(term2, T, "t2b");n        term2 = builder.CreateFMul(term2, dpH, "term2");n        llvm::Value* result = builder.CreateFAdd(term1, term2, "dG");n        builder.CreateRet(result);n        return fn;n    }nn    llvm::Function* create_boyer() {n        llvm::FunctionType* ty = llvm::FunctionType::get(builder.getDoubleTy(), {builder.getDoubleTy(), builder.getDoubleTy()}, false);n        llvm::Function* fn = llvm::Function::Create(ty, llvm::Function::ExternalLinkage, "boyer_ATP", module.get());n        llvm::BasicBlock* entry = llvm::BasicBlock::Create(context, "entry", fn);n        builder.SetInsertPoint(entry);n        llvm::Argument* flux = fn->getArg(0);n        llvm::Argument* n = fn->getArg(1);n        llvm::Value* result = builder.CreateFDiv(builder.CreateFMul(flux, n), builder.getConstantFP(llvm::APFloat(3.0)), "ATP");n        builder.CreateRet(result);n        return fn;n    }nn    llvm::Function* create_membrane_absorb() {n        llvm::FunctionType* ty = llvm::FunctionType::get(builder.getDoubleTy(), {builder.getDoubleTy(), builder.getDoubleTy()}, false);n        llvm::Function* fn = llvm::Function::Create(ty, llvm::Function::ExternalLinkage, "membrane_absorb", module.get());n        llvm::BasicBlock* entry = llvm::BasicBlock::Create(context, "entry", fn);n        llvm::BasicBlock* compute = llvm::BasicBlock::Create(context, "compute", fn);n        llvm::BasicBlock* decide = llvm::BasicBlock::Create(context, "decide", fn);n        builder.SetInsertPoint(entry);n        llvm::Argument* signal = fn->getArg(0);n        llvm::Argument* rw = fn->getArg(1);n        builder.CreateBr(compute);n        builder.SetInsertPoint(compute);n        llvm::Value* dE = builder.CreateCall(create_gouterman(), {signal}, "dE");n        llvm::Value* k_ET = builder.CreateCall(create_forster(), {builder.getConstantFP(llvm::APFloat(1.0)), signal}, "k_ET");n        llvm::Value* marcus_k = builder.CreateCall(create_marcus(), {dE, signal}, "marcus_k");n        llvm::Value* mitchell_dG = builder.CreateCall(create_mitchell(), {builder.getConstantFP(llvm::APFloat(1.0)), dE, signal}, "mitchell_dG");n        llvm::Value* boyer_ATP = builder.CreateCall(create_boyer(), {dE, marcus_k}, "boyer_ATP");n        builder.CreateBr(decide);n        builder.SetInsertPoint(decide);n        llvm::Value* speed = builder.CreateFAdd(builder.CreateFMul(boyer_ATP, mitchell_dG), k_ET, "speed");n        llvm::Value* cmp = builder.CreateFCmpOGE(speed, rw, "cmp");n        llvm::Value* decision = builder.CreateSelect(cmp, builder.getConstantFP(llvm::APFloat(1.0)), builder.getConstantFP(llvm::APFloat(0.0)), "decision");n        builder.CreateRet(decision);n        return fn;n    }nn    void finalize() {n        llvm::verifyModule(*module);n    }nn    std::string printIR() {n        std::string str;n        llvm::raw_string_ostream os(str);n        module->print(os, nullptr);n        return str;n    }n};nn} // namespace csosnnint main(int argc, char** argv) {n    if (argc < 2) {n        std::cerr << "Usage: csos_codegen <spec.csos> [output.ll]" << std::endl;n        return 1;n    }nn    std::string spec_path = argv[1];n    std::string output_path = argc > 2 ? argv[2] : "csos.ll";nn    csos::SpecParser parser;n    if (!parser.parse(spec_path)) {n        std::cerr << "Failed to parse: " << spec_path << std::endl;n        return 1;n    }n    std::cerr << "Parsed " << parser.atoms.size() << " atoms, " << parser.rings.size() << " rings" << std::endl;nn    csos::Codegen codegen;n    codegen.create_membrane_absorb();n    codegen.finalize();nn    std::string ir = codegen.printIR();n    std::ofstream out(output_path);n    out << ir;n    out.close();nn    std::cerr << "Generated: " << output_path << std::endl;n    return 0;n}n